; --- MODEM_STATUS_CHECK ---
; Check modem status register
MODEM_STATUS_CHECK:
    AND #$7F
    CMP #$20
    BCS L94B2
    ORA #$40
    BNE L94C0

; ============================================================
; MODEM_REG_WRITE_WAIT
; ============================================================
