; --- MODEM_REG_READ_STATUS ---
; Read modem status into $C100 buffer
MODEM_REG_READ_STATUS:
    LDY #$00
L94D7:
    JSR L96CC
    STA $C100,Y
    INY
    BCC L94D7
    LDA $8034
    RTS                                 ; MODEM_REG_SELECT

; --- MODEM_WAIT_READY ---
; Wait for modem TX ready, then send byte
MODEM_WAIT_READY:
    PHA
    LDX #$00
L94E7:
    JSR MODEM_REG_READ
    TAX

; ============================================================
; MODEM_REG_READ
; ============================================================
    BPL L94E7
    PLA                                 ; MODEM_REG_SELECT
    LDX #$04

; --- MODEM_REG_WRITE ---
; Write value to modem register (X=reg, A=value)
MODEM_REG_WRITE:
    PHP                                 ; MODEM_DATA
    SEI
    STX ACIA_DATA
    STA ACIA_STATUS
    PLP
    RTS

; --- MODEM_REG_READ ---
; Read modem register (X=reg, returns A=value)
MODEM_REG_READ:
    PHP
    SEI
    STX ACIA_DATA
    LDA ACIA_STATUS
    LDA ACIA_STATUS
    PLP
    RTS
